package etcdserver

import "go.etcd.io/raft/v3"

// InMemoryRaftLog is an in-memory implementation of the Raft log.
// It is a type alias for raft.MemoryStorage to provide a more descriptive name.
type InMemoryRaftLog = raft.MemoryStorage

// NewInMemoryRaftLog creates a new in-memory Raft log.
func NewInMemoryRaftLog() *InMemoryRaftLog {
	return raft.NewMemoryStorage()
}

code_changes.new_string:
type raftNodeConfig struct {
	lg *zap.Logger

	// to check if msg receiver is removed from cluster
	isIDRemoved func(id uint64) bool
	raft.Node
	raftStorage *InMemoryRaftLog
	storage     serverstorage.Storage
	heartbeat   time.Duration // for logging
	// transport specifies the transport to send and receive msgs to members.
	// Sending messages MUST NOT block. It is okay to drop messages, since
	// clients should timeout and reissue their messages.
	// If transport is nil, server will panic.
	transport rafthttp.Transporter
}

