code_changes.new_string:
func (wal *bootstrappedWAL) MemoryStorage() *InMemoryRaftLog {
	s := NewInMemoryRaftLog()
	if wal.snapshot != nil {
		s.ApplySnapshot(*wal.snapshot)
	}
	if wal.st != nil {
		s.SetHardState(*wal.st)
	}
	if len(wal.ents) != 0 {
		s.Append(wal.ents)
	}
	return s
}

